() => {
  // Look for any sample-related buttons or links
  const all = Array.from(document.querySelectorAll('button, a, [role="button"]'));
  return all.map(el => ({ tag: el.tagName, text: el.textContent?.trim().substring(0, 100), id: el.id, class: el.className }));
}

() => {
  // Get the full HTML to search for sample content
  const html = document.documentElement.innerHTML;
  const matches = [];
  const patterns = ['sample', 'try it', 'example', 'demo', 'load'];
  patterns.forEach(p => {
    const idx = html.toLowerCase().indexOf(p);
    if (idx >= 0) {
      matches.push({ pattern: p, context: html.substring(Math.max(0, idx-50), idx+100) });
    }
  });
  return matches;
}

